CREATE POLICY "Service role can access all consolidation logs" ON public.memory_consolidation_log USING ((auth.role() = 'service_role'::text));

CREATE POLICY "Service role can access all memory facts" ON public.memory_facts USING ((auth.role() = 'service_role'::text));

CREATE POLICY "Service role can access all memory sessions" ON public.memory_sessions USING ((auth.role() = 'service_role'::text));

CREATE POLICY "Service role can access all research logs" ON public.research_logs USING ((auth.role() = 'service_role'::text));

CREATE POLICY "Service role can access all research results" ON public.research_results USING ((auth.role() = 'service_role'::text));

CREATE POLICY "Service role can access all research sessions" ON public.research_sessions USING ((auth.role() = 'service_role'::text));

CREATE POLICY "Service role can access all research sources" ON public.research_sources USING ((auth.role() = 'service_role'::text));

CREATE POLICY "Users can view logs for their sessions" ON public.research_logs FOR SELECT USING ((EXISTS ( SELECT 1
   FROM public.research_sessions
  WHERE ((research_sessions.id = research_logs.session_id) AND (research_sessions.user_id = auth.uid())))));

CREATE POLICY "Users can view results for their sessions" ON public.research_results FOR SELECT USING ((EXISTS ( SELECT 1
   FROM public.research_sessions
  WHERE ((research_sessions.id = research_results.session_id) AND (research_sessions.user_id = auth.uid())))));

CREATE POLICY "Users can view sources for their sessions" ON public.research_sources FOR SELECT USING ((EXISTS ( SELECT 1
   FROM public.research_sessions
  WHERE ((research_sessions.id = research_sources.session_id) AND (research_sessions.user_id = auth.uid())))));

CREATE POLICY "Users can view their own research sessions" ON public.research_sessions FOR SELECT USING ((auth.uid() = user_id));

